using System.Collections.Generic;

namespace TestProject.Models;

public sealed record FileEntryDto(string Name, string Path, bool IsDirectory, long Size, System.DateTime LastModified);

public sealed record BrowseResultDto(string Path, string? Parent, IReadOnlyList<FileEntryDto> Entries, int FolderCount, int FileCount, long TotalSize);

public sealed record SearchResultDto(string Query, string Path, IReadOnlyList<FileEntryDto> Results);

public sealed record MoveRequest(string SourcePath, string DestinationPath);

public sealed record CopyRequest(string SourcePath, string DestinationPath);

{
  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "test": "vitest run",
    "watch": "tsc --watch"
  },
  "devDependencies": {
    "typescript": "^5.6.3",
    "vitest": "^2.1.4",
    "happy-dom": "^15.7.4"
  }
}

namespace TestProject {
    public class Program {
        public static void Main(string[] args) {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.

            builder.Services.AddControllers();

            // Bind the FileService configuration section and register the
            // path-safe IFileService implementation so controllers can be
            // activated through dependency injection.
            builder.Services.Configure<TestProject.FileServiceOptions>(
                builder.Configuration.GetSection("FileService"));
            builder.Services.AddSingleton<TestProject.Services.IFileService, TestProject.Services.FileService>();

            var app = builder.Build();

            // Configure the HTTP request pipeline.

            app.UseHttpsRedirection();

            app.UseDefaultFiles();

            app.UseStaticFiles();

            app.MapControllers();

            app.MapFallbackToFile("index.html");

            app.Run();
        }
    }
}

import { mkdir, copyFile } from 'node:fs/promises';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const rootDir = resolve(__dirname, '..');
const srcDir = resolve(rootDir, 'src');
const outDir = resolve(rootDir, 'wwwroot', 'dist');

async function main() {
  // Ensure output directory exists
  await mkdir(outDir, { recursive: true });

  const srcPath = resolve(srcDir, 'app.css');
  const destPath = resolve(outDir, 'app.css');

  try {
    await copyFile(srcPath, destPath);
  } catch {
    // If src/app.css doesn't exist, exit 0 silently
    process.exit(0);
  }
}

main();

